236:     private static void resetToLastCommittedPositions(KafkaConsumer<String, String> consumer) {
237:         final Map<TopicPartition, OffsetAndMetadata> committed = consumer.committed(consumer.assignment());
238:         consumer.assignment().forEach(tp -> {
239:             OffsetAndMetadata offsetAndMetadata = committed.get(tp);
240:             if (offsetAndMetadata != null)
