305:     public static void runEventLoop(Namespace parsedArgs) {
306:         final String transactionalId = parsedArgs.getString("transactionalId");
307:         final String outputTopic = parsedArgs.getString("outputTopic");
308: 
309:         String consumerGroup = parsedArgs.getString("consumerGroup");
310: 
311:         final KafkaProducer<String, String> producer = createProducer(parsedArgs);
312:         final KafkaConsumer<String, String> consumer = createConsumer(parsedArgs);
313: 
314:         final AtomicLong remainingMessages = new AtomicLong(
315:             parsedArgs.getInt("maxMessages") == -1 ? Long.MAX_VALUE : parsedArgs.getInt("maxMessages"));
316: 
317:         boolean groupMode = parsedArgs.getBoolean("groupMode");
318:         String topicName = parsedArgs.getString("inputTopic");
319:         final AtomicLong numMessagesProcessedSinceLastRebalance = new AtomicLong(0);
320:         final AtomicLong totalMessageProcessed = new AtomicLong(0);
321:         if (groupMode) {
322:             consumer.subscribe(Collections.singleton(topicName), new ConsumerRebalanceListener() {
323:                 @Override
324:                 public void onPartitionsRevoked(Collection<TopicPartition> partitions) {
325:                 }
326: 
327:                 @Override
328:                 public void onPartitionsAssigned(Collection<TopicPartition> partitions) {
329:                     remainingMessages.set(partitions.stream()
330:                         .mapToLong(partition -> messagesRemaining(consumer, partition)).sum());
331:                     numMessagesProcessedSinceLastRebalance.set(0);
332:                     // We use message cap for remaining here as the remainingMessages are not set yet.
333:                     System.out.println(statusAsJson(
334:                         "RebalanceComplete",
335:                         totalMessageProcessed.get(),
336:                         numMessagesProcessedSinceLastRebalance.get(),
337:                         remainingMessages.get(),
338:                         transactionalId
339:                     ));
340:                 }
341:             });
342:         } else {
343:             TopicPartition inputPartition = new TopicPartition(topicName, parsedArgs.getInt("inputPartition"));
344:             consumer.assign(singleton(inputPartition));
345:             remainingMessages.set(Math.min(messagesRemaining(consumer, inputPartition), remainingMessages.get()));
346:         }
347: 
348:         final boolean enableRandomAborts = parsedArgs.getBoolean("enableRandomAborts");
349: 
350:         producer.initTransactions();
351: 
352:         final AtomicBoolean isShuttingDown = new AtomicBoolean(false);
353: 
354:         Exit.addShutdownHook("transactional-message-copier-shutdown-hook", () -> {
355:             isShuttingDown.set(true);
356:             consumer.wakeup();
357:             System.out.println(statusAsJson(
358:                 "ShutdownComplete",
359:                 totalMessageProcessed.get(),
360:                 numMessagesProcessedSinceLastRebalance.get(),
361:                 remainingMessages.get(),
362:                 transactionalId
363:             ));
364:         });
365: 
366:         final boolean useGroupMetadata = parsedArgs.getBoolean("useGroupMetadata");
367:         try {
368:             Random random = new Random();
369:             while (!isShuttingDown.get() && remainingMessages.get() > 0) {
370:                 System.out.println(statusAsJson(
371:                     "ProcessLoop",
372:                     totalMessageProcessed.get(),
373:                     numMessagesProcessedSinceLastRebalance.get(),
374:                     remainingMessages.get(),
375:                     transactionalId
376:                 ));
377: 
378:                 ConsumerRecords<String, String> records = consumer.poll(Duration.ofMillis(200));
379:                 if (records.count() > 0) {
380:                     try {
381:                         producer.beginTransaction();
382: 
383:                         for (ConsumerRecord<String, String> record : records) {
384:                             producer.send(producerRecordFromConsumerRecord(outputTopic, record));
385:                         }
386: 
387:                         long messagesSentWithinCurrentTxn = records.count();
388: 
389:                         ConsumerGroupMetadata groupMetadata = useGroupMetadata ? consumer.groupMetadata() : new ConsumerGroupMetadata(consumerGroup);
390:                         producer.sendOffsetsToTransaction(consumerPositions(consumer), groupMetadata);
391: 
392:                         if (enableRandomAborts && random.nextInt() % 3 == 0) {
393:                             abortTransactionAndResetPosition(producer, consumer);
394:                         } else {
395:                             producer.commitTransaction();
396:                             remainingMessages.getAndAdd(-messagesSentWithinCurrentTxn);
397:                             numMessagesProcessedSinceLastRebalance.getAndAdd(messagesSentWithinCurrentTxn);
398:                             totalMessageProcessed.getAndAdd(messagesSentWithinCurrentTxn);
399:                         }
400:                     } catch (ProducerFencedException e) {
401:                         throw new KafkaException(String.format("The transactional.id %s has been claimed by another process", transactionalId), e);
402:                     } catch (KafkaException e) {
403:                         log.debug("Aborting transaction after catching exception", e);
404:                         abortTransactionAndResetPosition(producer, consumer);
405:                     }
406:                 }
407:             }
408:         } catch (WakeupException e) {
409:             if (!isShuttingDown.get()) {
410:                 // Let the exception propagate if the exception was not raised
411:                 // as part of shutdown.
412:                 throw e;
413:             }
414:         } finally {
415:             Utils.closeQuietly(producer, "producer");
416:             Utils.closeQuietly(consumer, "consumer");
417:         }
418:     }
419: }
