import org.apache.kafka.clients.consumer.ConsumerConfig;
import org.apache.kafka.clients.consumer.ConsumerRecord;
import org.apache.kafka.clients.consumer.ConsumerRecords;
import org.apache.kafka.clients.consumer.KafkaConsumer;
import org.apache.kafka.common.errors.WakeupException;
import org.apache.kafka.common.serialization.StringDeserializer;

import java.time.Duration;
import java.util.Collections;
import java.util.Properties;
import java.util.Set;
import java.util.HashSet;

/**
 * InventoryConsumer consumes messages from the "inventory-updates" Kafka topic
 * and processes them idempotently. It uses manual offset commits (commitSync)
 * after processing each batch and handles WakeupException for clean shutdown.
 *
 * Patterns follow the Kafka codebase examples in:
 *   - examples/src/main/java/kafka/examples/Consumer.java
 *   - tools/src/main/java/org/apache/kafka/tools/TransactionalMessageCopier.java
 *   - clients/src/main/java/org/apache/kafka/clients/consumer/KafkaConsumer.java
 */
public class InventoryConsumer implements Runnable {
    private static final String TOPIC = "inventory-updates";

    private final KafkaConsumer<String, String> consumer;
    // Track processed message keys for idempotency
    private final Set<String> processedIds = new HashSet<>();
    private volatile boolean closed = false;

    public InventoryConsumer(String bootstrapServers, String groupId) {
        Properties props = new Properties();
        // Use ConsumerConfig constants (not string literals) for all configuration keys
        props.put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, bootstrapServers);
        props.put(ConsumerConfig.GROUP_ID_CONFIG, groupId);
        props.put(ConsumerConfig.CLIENT_ID_CONFIG, "inventory-consumer-client");
        // Disable auto commit so we control exactly when offsets are committed
        props.put(ConsumerConfig.ENABLE_AUTO_COMMIT_CONFIG, "false");
        props.put(ConsumerConfig.AUTO_OFFSET_RESET_CONFIG, "earliest");
        props.put(ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class.getName());
        props.put(ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class.getName());
        props.put(ConsumerConfig.SESSION_TIMEOUT_MS_CONFIG, "10000");
        props.put(ConsumerConfig.MAX_POLL_INTERVAL_MS_CONFIG, "300000");

        this.consumer = new KafkaConsumer<>(props);
    }

    @Override
    public void run() {
        try {
            consumer.subscribe(Collections.singleton(TOPIC));

            while (!closed) {
                // Use poll(Duration) API (not the deprecated poll(long))
                ConsumerRecords<String, String> records = consumer.poll(Duration.ofMillis(1000));

                for (ConsumerRecord<String, String> record : records) {
                    processRecord(record);
                }

                if (!records.isEmpty()) {
                    // commitSync() after processing each batch for at-least-once delivery
                    consumer.commitSync();
                }
            }
        } catch (WakeupException e) {
            // Handle WakeupException for clean shutdown; ignore if we are closing
            if (!closed) {
                throw e;
            }
        } finally {
            consumer.close();
        }
    }

    /**
     * Process a single inventory update record idempotently.
     * Records with the same key (messageId) are deduplicated.
     */
    private void processRecord(ConsumerRecord<String, String> record) {
        String messageId = record.key();

        // Idempotency check: skip already-processed messages
        if (messageId != null && processedIds.contains(messageId)) {
            System.out.printf("Skipping duplicate record: key=%s, offset=%d%n",
                    messageId, record.offset());
            return;
        }

        // Process the inventory update
        System.out.printf("Processing inventory update: topic=%s, partition=%d, offset=%d, key=%s, value=%s%n",
                record.topic(), record.partition(), record.offset(), record.key(), record.value());

        // Mark as processed for idempotency tracking
        if (messageId != null) {
            processedIds.add(messageId);
        }
    }

    /**
     * Trigger a clean shutdown by waking up the consumer.
     * The poll() call will throw WakeupException which is handled in run().
     */
    public void shutdown() {
        closed = true;
        consumer.wakeup();
    }

    public static void main(String[] args) throws InterruptedException {
        String bootstrapServers = args.length > 0 ? args[0] : "localhost:9092";
        String groupId = args.length > 1 ? args[1] : "inventory-consumer-group";

        InventoryConsumer inventoryConsumer = new InventoryConsumer(bootstrapServers, groupId);

        // Register shutdown hook for clean shutdown
        Runtime.getRuntime().addShutdownHook(new Thread(inventoryConsumer::shutdown));

        inventoryConsumer.run();
    }
}

